@@ -0,0 +1,209 @@
+diff --git a/crates/fsqlite-core/src/connection.rs b/crates/fsqlite-core/src/connection.rs
+index 827108c0..4936ee23 100644
+--- a/crates/fsqlite-core/src/connection.rs
++++ b/crates/fsqlite-core/src/connection.rs
+@@ -2976,6 +2976,13 @@ struct MaterializedTempTable {
+ enum PreparedDirectSimpleInsertExpr {
+     Literal(SqliteValue),
+     Placeholder(usize),
++    ConcatTextLiteral(String),
++    BinaryOpParamLiteral {
++        param_one_based: usize,
++        op: BinaryOp,
++        literal: SqliteValue,
++        param_on_left: bool,
++    },
+     ConcatChain(Vec<Self>),
+     BinaryOp {
+         left: Box<Self>,
+@@ -15518,6 +15525,11 @@ impl Connection {
+                         Self::append_prepared_direct_simple_insert_text(text_scratch, value);
+                     }
+                 }
++                PreparedDirectSimpleInsertExpr::ConcatTextLiteral(value) => {
++                    if !saw_null {
++                        text_scratch.push_str(value);
++                    }
++                }
+                 _ => {
+                     let value =
+                         Self::eval_prepared_direct_simple_insert_expr(segment, params, None)?;
+@@ -21031,18 +21043,7 @@ impl Connection {
+     ) -> Option<PreparedDirectSimpleInsertExpr> {
+         match expr {
+             Expr::Literal(literal, _) => {
+-                let value = match literal {
+-                    Literal::Null => SqliteValue::Null,
+-                    Literal::Integer(value) => SqliteValue::Integer(*value),
+-                    Literal::Float(value) => SqliteValue::Float(*value),
+-                    Literal::String(value) => SqliteValue::Text(value.clone().into()),
+-                    Literal::Blob(value) => SqliteValue::Blob(value.clone().into()),
+-                    Literal::True => SqliteValue::Integer(1),
+-                    Literal::False => SqliteValue::Integer(0),
+-                    Literal::CurrentTimestamp | Literal::CurrentDate | Literal::CurrentTime => {
+-                        return None;
+-                    }
+-                };
++                let value = Self::prepared_direct_simple_insert_literal_value(literal)?;
+                 Some(PreparedDirectSimpleInsertExpr::Literal(value))
+             }
+             Expr::Placeholder(PlaceholderType::Numbered(index), _) => {
+@@ -21059,11 +21060,36 @@ impl Connection {
+             }
+             Expr::BinaryOp {
+                 left, op, right, ..
+-            } => Some(PreparedDirectSimpleInsertExpr::BinaryOp {
+-                left: Box::new(Self::compile_prepared_direct_simple_insert_expr(left)?),
+-                op: *op,
+-                right: Box::new(Self::compile_prepared_direct_simple_insert_expr(right)?),
+-            }),
++            } => {
++                if let Some(param_one_based) =
++                    Self::prepared_direct_simple_insert_numbered_placeholder(left)
++                    && let Some(literal) =
++                        Self::prepared_direct_simple_insert_literal_operand(right)
++                {
++                    return Some(PreparedDirectSimpleInsertExpr::BinaryOpParamLiteral {
++                        param_one_based,
++                        op: *op,
++                        literal,
++                        param_on_left: true,
++                    });
++                }
++                if let Some(literal) = Self::prepared_direct_simple_insert_literal_operand(left)
++                    && let Some(param_one_based) =
++                        Self::prepared_direct_simple_insert_numbered_placeholder(right)
++                {
++                    return Some(PreparedDirectSimpleInsertExpr::BinaryOpParamLiteral {
++                        param_one_based,
++                        op: *op,
++                        literal,
++                        param_on_left: false,
++                    });
++                }
++                Some(PreparedDirectSimpleInsertExpr::BinaryOp {
++                    left: Box::new(Self::compile_prepared_direct_simple_insert_expr(left)?),
++                    op: *op,
++                    right: Box::new(Self::compile_prepared_direct_simple_insert_expr(right)?),
++                })
++            }
+             Expr::UnaryOp {
+                 op, expr: inner, ..
+             } => Some(PreparedDirectSimpleInsertExpr::UnaryOp {
+@@ -21102,6 +21128,36 @@ impl Connection {
+         }
+     }
+ 
++    fn prepared_direct_simple_insert_literal_value(literal: &Literal) -> Option<SqliteValue> {
++        match literal {
++            Literal::Null => Some(SqliteValue::Null),
++            Literal::Integer(value) => Some(SqliteValue::Integer(*value)),
++            Literal::Float(value) => Some(SqliteValue::Float(*value)),
++            Literal::String(value) => Some(SqliteValue::Text(value.clone().into())),
++            Literal::Blob(value) => Some(SqliteValue::Blob(value.clone().into())),
++            Literal::True => Some(SqliteValue::Integer(1)),
++            Literal::False => Some(SqliteValue::Integer(0)),
++            Literal::CurrentTimestamp | Literal::CurrentDate | Literal::CurrentTime => None,
++        }
++    }
++
++    fn prepared_direct_simple_insert_literal_operand(expr: &Expr) -> Option<SqliteValue> {
++        match expr {
++            Expr::Literal(literal, _) => Self::prepared_direct_simple_insert_literal_value(literal),
++            _ => None,
++        }
++    }
++
++    fn prepared_direct_simple_insert_numbered_placeholder(expr: &Expr) -> Option<usize> {
++        match expr {
++            Expr::Placeholder(PlaceholderType::Numbered(index), _) => {
++                let one_based = usize::try_from(*index).ok()?;
++                (one_based != 0).then_some(one_based)
++            }
++            _ => None,
++        }
++    }
++
+     fn collect_prepared_direct_simple_insert_concat_segments(
+         expr: &Expr,
+         segments: &mut Vec<PreparedDirectSimpleInsertExpr>,
+@@ -21117,6 +21173,12 @@ impl Connection {
+                 Self::collect_prepared_direct_simple_insert_concat_segments(right, segments)?;
+                 Some(())
+             }
++            Expr::Literal(Literal::String(value), _) => {
++                segments.push(PreparedDirectSimpleInsertExpr::ConcatTextLiteral(
++                    value.clone(),
++                ));
++                Some(())
++            }
+             _ => {
+                 segments.push(Self::compile_prepared_direct_simple_insert_expr(expr)?);
+                 Some(())
+@@ -21134,6 +21196,23 @@ impl Connection {
+             PreparedDirectSimpleInsertExpr::Placeholder(one_based) => {
+                 Ok(Self::prepared_direct_simple_insert_param(params, *one_based)?.clone())
+             }
++            PreparedDirectSimpleInsertExpr::ConcatTextLiteral(value) => {
++                Ok(SqliteValue::Text(value.as_str().into()))
++            }
++            PreparedDirectSimpleInsertExpr::BinaryOpParamLiteral {
++                param_one_based,
++                op,
++                literal,
++                param_on_left,
++            } => {
++                let param = Self::prepared_direct_simple_insert_param(params, *param_one_based)?;
++                let (left, right) = if *param_on_left {
++                    (param, literal)
++                } else {
++                    (literal, param)
++                };
++                Ok(crate::connection::eval_binary_op(left, *op, right))
++            }
+             PreparedDirectSimpleInsertExpr::ConcatChain(segments) => {
+                 if let Some(text_scratch) = reusable_concat_text_scratch {
+                     Self::eval_prepared_direct_simple_insert_concat_chain(
+@@ -107855,16 +107934,35 @@ mod pager_routing_tests {
+             direct.compiled_row_values.is_some(),
+             "benchmark-style direct insert should compile its row expressions once at prepare time"
+         );
++        let exprs = direct
++            .compiled_row_values
++            .as_ref()
++            .expect("checked compiled direct row expressions above");
+         assert!(
+-            direct
+-                .compiled_row_values
+-                .as_ref()
+-                .is_some_and(|exprs| exprs.iter().any(|expr| matches!(
+-                    expr,
+-                    PreparedDirectSimpleInsertExpr::ConcatChain(parts) if parts.len() >= 2
+-                ))),
++            exprs.iter().any(|expr| matches!(
++                expr,
++                PreparedDirectSimpleInsertExpr::ConcatChain(parts)
++                    if parts.len() >= 2
++                        && parts.iter().any(|part| matches!(
++                            part,
++                            PreparedDirectSimpleInsertExpr::ConcatTextLiteral(text)
++                                if text == "user_"
++                        ))
++            )),
+             "benchmark-style direct insert should flatten concat-heavy expressions into one-pass chains"
+         );
++        assert!(
++            exprs.iter().any(|expr| matches!(
++                expr,
++                PreparedDirectSimpleInsertExpr::BinaryOpParamLiteral {
++                    param_one_based: 1,
++                    op: BinaryOp::Multiply,
++                    literal: SqliteValue::Float(factor),
++                    param_on_left: true,
++                } if (*factor - 0.137).abs() < f64::EPSILON
++            )),
++            "benchmark-style direct insert should compile ?N op literal without cloning both operands per row"
++        );
+     }
+ 
+     #[test]
